using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [BREAKING] HasIndex throws in EF Core 9 — Cosmos indexes are
        // managed via indexing policy in the Azure portal, not EF.
        // REMOVED: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // [BREAKING] EF Core 9 renamed the default discriminator JSON
            // property from "Discriminator" to "$type". Existing 500K docs
            // use "Discriminator", and direct SQL queries filter on it.
            // Keep the old name so reads/writes stay compatible.
            entity.HasDiscriminator<string>("Discriminator");

            // [BREAKING] EF Core 9 changed id synthesis from
            // "Product|123" to just "123". Existing documents still carry
            // the old format. Preserve it with a custom ValueGenerator.
            entity.Property<string>("__id")
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 id format: "{EntityTypeName}|{PrimaryKey}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var typeName = entry.Metadata.ShortName();
        var pk = entry.Property("Id").CurrentValue;
        return $"{typeName}|{pk}";
    }
}

